8230	\begin{lemma}[The category of schemes is finitary extensive]
8231	  \label{lem:finitaryExtensive_scheme_mathlib}
8232	  \lean{AlgebraicGeometry.instFinitaryExtensiveScheme}
8233	  \mathlibok
8234	  \textit{Provided by Mathlib.}
8235	  The category \(\operatorname{Scheme}\) is finitary extensive: finite coproducts are disjoint
8236	  and universal (stable under pullback). In particular it is finitary pre-extensive and has
8237	  finite coproducts and pullbacks, so the abstract distributivity of
8238	  Lemma~\ref{lem:isIso_sigmaDesc_map_mathlib} applies at \(\mathcal{C} = \operatorname{Scheme}\).
8239	\end{lemma}
8240	
8241	\begin{lemma}[Coproducts distribute over the binary fibre product]
8242	  \label{lem:isIso_sigmaDesc_map_mathlib}
8243	  \lean{CategoryTheory.FinitaryPreExtensive.isIso_sigmaDesc_map}
8244	  \mathlibok
8245	  \textit{Provided by Mathlib.}
8246	  In a finitary pre-extensive category with pullbacks, for finite index types \(\iota, \iota'\),
8247	  a base \(S\), and families \((X_i \to S)_i\), \((Y_j \to S)_j\), the canonical map
8248	  \(\coprod_{(i,j)} (X_i \times_S Y_j) \to (\coprod_i X_i) \times_S (\coprod_j Y_j)\),
8249	  \(\operatorname{Sigma.desc}\) of the pullback maps, is an isomorphism. Taking one family to be a
8250	  singleton gives the one-sided distributivity
8251	  \((\coprod_i X_i) \times_S Y \cong \coprod_i (X_i \times_S Y)\) used in the induction of
8252	  Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8253	\end{lemma}
8254	
8255	\begin{lemma}[Pullback of two open immersions is the intersection open]
8256	  \label{lem:isPullback_opens_inf_mathlib}
8257	  \lean{AlgebraicGeometry.isPullback_opens_inf}
8258	  \mathlibok
8259	  \textit{Provided by Mathlib.}
8260	  For two opens \(U, V\) of a scheme \(X\), the square with vertex \((U \sqcap V).\mathrm{toScheme}\)
8261	  and the two \(\operatorname{homOfLE}\) inclusions into \(U\) and \(V\) is a pullback of the open
8262	  immersions \(U.\iota, V.\iota\). Equivalently \(\operatorname{pullback} U.\iota\,V.\iota \cong
8263	  (U \sqcap V).\mathrm{toScheme}\): the fibre product of open immersions over \(X\) is the
8264	  intersection of their images.
8265	\end{lemma}
8266	
8267	\begin{lemma}[A wide pullback over a terminal base is the product of its legs]
8268	  \label{lem:widePullbackCone_isLimitOfFan_mathlib}
8269	  \lean{CategoryTheory.Limits.WidePullbackCone.isLimitOfFan}
8270	  \mathlibok
8271	  \textit{Provided by Mathlib.}
8272	  When the base of a wide pullback is a terminal object, a limiting fan of the legs is a limit of
8273	  the wide-pullback diagram. Hence in \(\operatorname{Over} S\) --- where \(\operatorname{Over.mk}
8274	  (\mathrm{id}_S)\) is terminal --- the wide pullback over \(S\) of a family is the product of the
8275	  legs in the slice, which is what lets the fibre power over \(S\) be treated as an iterated
8276	  product in Lemma~\ref{lem:coproduct_distrib_fibrePower}.
8277	\end{lemma}
8278	
8279	\begin{lemma}[The identity arrow is terminal in the slice category]
8280	  \label{lem:over_mkIdTerminal_mathlib}
8281	  \lean{CategoryTheory.Over.mkIdTerminal}
8282	  \mathlibok
8283	  \textit{Provided by Mathlib.}
8284	  For an object \(S\) of a category, \(\operatorname{Over.mk}(\mathrm{id}_S)\) is a terminal object
8285	  of the slice category \(\operatorname{Over} S\). This is what makes the base of a wide pullback
8286	  over \(S\) terminal in the slice, so that
8287	  Lemma~\ref{lem:widePullbackCone_isLimitOfFan_mathlib} exhibits the fibre power over \(S\) as the
8288	  product in \(\operatorname{Over} S\) in Lemma~\ref{lem:widePullback_overX_eq_prod}.
8289	\end{lemma}
